<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            reportPath: null,
            parameter: [],
            clientIds: '',
            LocationId: 0,
            loadKey: 0,
            FormSchema: [{
                layoutType: "triple",
                Data: [{
                    astype: "MultiSelectField",
                    label: this.$t("ClientName"),
                    name: "Clientname",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('Client'),
                    mode: "tag",
                    config: {
                        options: [],
                        onChange: this.onChangeDropdown,
                        onRemove: this.removeRecord
                    }
                },
                {
                    astype: "MultiSelectField",
                    label: this.$t("UtilityName"),
                    name: "UtilityName",
                    value: "",
                    placeholder: this.$t('Select'),
                    mode: "tag",
                    config: {
                        options: [],
                        onChange: this.GetInvoiceGrouping
                    }
                },
                {
                    astype: "MultiSelectField",
                    label: this.$t("Invoice grouping"),
                    name: "Invoicegrouping",
                    value: "",
                    placeholder: this.$t('Select'),
                    mode: "tag",
                    config: {
                        options: [],
                    }
                }
                ]
            },
            {
                layoutType: "triple",
                Data: [{
                    astype: "SelectField",
                    label: this.$t("Status"),
                    name: "Status",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('Status'),
                    mode: "tag",
                    config: {
                        options: [{
                            name: 'Billed Records',
                            value: "1"
                        }, {
                            name: 'Unbilled Records',
                            value: "2"
                        }]
                    },
                    validationRules: {
                        "required": true
                    }
                },
                {
                    astype: "DateRangeField",
                    label: this.$t('Work_Date'),
                    name: "WorkDateFrom",
                    value: "",
                    placeholder: "",
                    config: {
                        format: "MM/DD/YYYY",
                        maxDate: false,
                        onChange: this.setTimerDate,
                        datePickerConfig: {
                            useCurrent: true,
                            showClear: true,
                            showClose: true,
                            allowInputToggle: false,
                            minDate: true,
                            maxDate: true,
                            widgetPositioning: {
                                horizontal: 'right',
                                vertical: 'bottom'
                            }
                        },
                        secondDatePickerConfig: {
                            useCurrent: false,
                            showClear: true,
                            showClose: true,
                            allowInputToggle: false,
                            minDate: true,
                            maxDate: true,
                            widgetPositioning: {
                                horizontal: 'right',
                                vertical: 'bottom'
                            }
                        },
                    },
                    validationRules: {
                        "required": false
                    },
                },
                {
                    astype: "SelectField",
                    label: this.$t("State"),
                    name: "State",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('State'),
                    mode: "tag",
                    config: {
                        options: [],
                    }
                }
                ]
            },
            {
                layoutType: "triple",
                Data: [{
                    astype: "SelectField",
                    label: this.$t("Frequency"),
                    name: "Frequency",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('Status'),
                    mode: "tag",
                    config: {
                        options: [{
                            name: 'Annually',
                            value: "annual"
                        }, {
                            name: 'Bi-Weekly',
                            value: "biweek"
                        }, {
                            name: 'Custom Date',
                            value: "custom"
                        }, {
                            name: 'Daily',
                            value: "daily"
                        }, {
                            name: 'Half yearly',
                            value: "halfyear"
                        }, {
                            name: 'Monthly',
                            value: "month"
                        }, {
                            name: 'Quarterly',
                            value: "quarterly"
                        }, {
                            name: 'Weekly',
                            value: "week"
                        }]
                    },
                    validationRules: {
                        "required": false
                    }
                },
                {
                    astype: "DateRangeField",
                    label: this.$t('Proccess Date'),
                    name: "ProccessDateFrom",
                    value: "",
                    placeholder: "",
                    config: {
                        format: "MM/DD/YYYY",
                        maxDate: false,
                        onChange: this.setTimerDate,
                        datePickerConfig: {
                            useCurrent: true,
                            showClear: true,
                            showClose: true,
                            allowInputToggle: false,
                            minDate: true,
                            maxDate: true,
                            widgetPositioning: {
                                horizontal: 'right',
                                vertical: 'bottom'
                            }
                        },
                        secondDatePickerConfig: {
                            useCurrent: false,
                            showClear: true,
                            showClose: true,
                            allowInputToggle: false,
                            minDate: true,
                            maxDate: true,
                            widgetPositioning: {
                                horizontal: 'right',
                                vertical: 'bottom'
                            }
                        },
                    },
                    validationRules: {
                        "required": false
                    },
                },
                {
                    astype: "multiSelectField",
                    label: this.$t("Work Code"),
                    name: "Workcode",
                    value: "",
                    placeholder: this.$t('Select'),
                    mode: "tag",
                    config: {
                        options: [],
                    }
                }
                ]
            }
            ],
            buttons: [{
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-search pr-2'></i>Search",
            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Clear all",
                onClick: this.ClearAll
            }
            ],
            DataLoaded: 0,
        };
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
        await vm.GetDDLStateList();
        await vm.GetWorkCodeInfo();
    },
    methods: {
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "Fromdate") {
                vm.$refs.BarcodeReport.updateProperty("ToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "ProccessFromdate") {
                vm.$refs.BarcodeReport.updateProperty("ProccessToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            vm.WorkDateFrom = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "value");
            vm.WorkDateTo = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "secondValue");
            vm.ProccessDateFrom = vm.$refs.BarcodeReport.getPropertyValue("ProccessDateFrom", "value");
            vm.ProccessDateTo = vm.$refs.BarcodeReport.getPropertyValue("ProccessDateFrom", "secondValue");

            let myObj = {
                reportName: "billedunbilledsummaryreport",
                ClientIds: e.Clientname.length > 0 ? e.Clientname.map(item => item.value).join(",") : '',
                fDate: vm.formatDate(vm.WorkDateFrom),
                tDate: vm.formatDate(vm.WorkDateTo),
                ProccessFromDate: vm.formatDate(vm.ProccessDateFrom),
                ProccessToDate: vm.formatDate(vm.ProccessDateTo),
                Invoicegrouping: e.Invoicegrouping.length > 0 ? e.Invoicegrouping.map(item => item.value).join(",") : '',
                State: e.State,
                Status: e.Status,
                Frequency: e.Frequency,
                UtilityIds: e.UtilityName.length > 0 ? e.UtilityName.map(item => item.value).join(",") : '',
                WorkCodeId: e.Workcode.length > 0 ? e.Workcode.map(item => item.value).join(",") : '',
            }
            //debugger;
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[2].Data[0].value = '';
            (vm.FormSchema)[2].Data[1].value = '';
            (vm.FormSchema)[2].Data[1].secondValue = '';
            (vm.FormSchema)[2].Data[2].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.currentReportParams = null;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        GetClient: async function () {
            var vm = this;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOM"&search=null&userId=null';
            DataServices.GetClient(params).then((response) => {
                if (response.data.length > 0) {
                    var ClientData = response.data;
                    ClientData.forEach(element => {
                        var Obj = {
                            name: element.CHILD_NAME,
                            value: element.CHILD_USER_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        removeRecord(event, field, meta) {
            this.onChangeDropdown('Remove', meta, event);
        },
        async onChangeDropdown(e, field, evt) {
            var vm = this;
            vm.isLoading = true;

            vm.clientIds = '';
            if (Array.isArray(field.value) && field.value.length > 0) {
                const combinedValue = field.value.map(item => item.value).join(",");
                vm.clientIds = combinedValue;
            }

            if (evt.value !== null && evt.value !== "" && e !== 'Remove') {
                vm.clientIds = evt.value;
            }

            if (e === 'Remove') {
                if (vm.clientIds) {
                    const clientIds = vm.clientIds.split(',');
                    const filteredclientIds = clientIds.filter(id => id !== evt.value.toString());
                    vm.clientIds = filteredclientIds.join(',');

                    let options = vm.FormSchema[0].Data[1].config.options;
                    let values = vm.FormSchema[0].Data[1].value;

                    let ids = vm.clientIds.split(',');

                    vm.FormSchema[0].Data[1].value = values.filter(v =>
                        options.some(o => ids.includes(o.parentId.toString()) && o.value == v.value)
                    );
                    vm.FormSchema[0].Data[1].config.options = [];
                    vm.FormSchema[0].Data[2].config.options = [];
                    vm.FormSchema[0].Data[2].value = '';
                    vm.GetInvoiceGrouping(vm.clientIds);
                }
            }

            var params = {
                clientId: '',
                configid: 0,
                Reqfrom: "BILLED_UNBILLED_REPORT",
                clientIds: vm.clientIds
            };
            var queryString = Object.keys(params).map(key => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`).join('&');

            await DataServices.GetUtilityByClient(queryString).then(function (response) {
                response.data.forEach(item => {
                    const obj = {
                        name: item.UTILITY_NAME,
                        value: item.UTILITY_ID,
                        parentId: vm.clientIds
                    }
                    vm.FormSchema[0].Data[1].config.options.push(obj);
                });
                vm.$refs.BarcodeReport.UpdateKeyValue();
                vm.isLoading = false;
            });
        },
        GetInvoiceGrouping: async function (x, y, z) {
            var vm = this;
            var url = `ClientId=${vm.clientIds}&UtilityIds=`;
            await DataServices.GetInvoiceGrouping(url).then((response) => {
                if (response.data.length > 0) {
                    var UtilityData = response.data;
                    UtilityData.forEach(element => {
                        var Obj = {
                            name: element.NOTE,
                            value: element.ID
                        }
                        vm.FormSchema[0].Data[2].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetDDLStateList: async function () {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            DataServices.GetDDLStateList(params).then((response) => {
                if (response.data.length > 0) {
                    var StateData = response.data;
                    StateData.forEach(item => {
                        vm.FormSchema[1].Data[2].config.options.push({
                            name: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                            value: item.ISO_CODE_3
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        GetWorkCodeInfo: async function () {
            var vm = this;
            DataServices.GetWorkCodeInfo().then((response) => {
                if (response.data.length > 0) {
                    var WorkCodeData = response.data;
                    WorkCodeData.forEach(item => {
                        vm.FormSchema[2].Data[2].config.options.push({
                            name: item.work_code,
                            value: item.work_code_id
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        // getStateNameById(stateId) {
        //     const stateField = this.FormSchema[1].Data[3];
        //     const match = stateField.config.options.find(s => s.value == stateId);
        //     return match ? match.name : '';
        // }
    }
};
</script>