<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                    <h4 class="modal-title">{{ $t('Invoice View Line Item') }}</h4>
                    <span class="user-guide">
                        <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG" role="button" aria-expanded="false" aria-controls="collapseExample">
                            <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}
                        </a>
                        <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                            <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                <div class="con" v-html="$t('User_Guide_Edit_Line_Item')"></div>
                            </div>
                        </div>
                    </span>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                <div class="modal-body">
                    <dynamic-form ref="dynamicform" lang="en" :buttons="buttons" :schema="FormSchema" :mandatorytext="$t('MandatoryString')">
                        <template v-slot:tgslot-TicketImage>
                            <span>
                                <a class="form-control border-0 px-0 viewicon text-primary" style="width:25px;" href="javascript:;" v-on:click="viewTicketImage">
                                    <em class="fa fa-eye fa-size"></em>
                                </a>
                            </span>
                        </template>
                    </dynamic-form>
                </div>
            </div>
        </div>
    </div>
    <transition name="modal">
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal d-block dialog" v-if="IsViewTicket">
                <div class="modal-dialog modal-lg">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h4 class="modal-title">{{ $t('TicketImage') }}</h4>
                            <button type="button" class="close" @click="CloseTemplate">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                        <div class="modal-body">
                            <div class="col-md-12">
                                <div class="listing" v-if="TicketContent">
                                    <div v-html="TicketContent" style="border: 1px solid #ddd; padding: 10px; margin-top: 10px; min-height: 50vh; overflow-y: auto;"></div>
                                </div>
                                <div v-else class="listing text-danger text-center border-0">
                                    {{ $t("NorecordfoundText") }}
                                </div>
                            </div>
                        </div>
                        <div class="modal-footer">
                            <button @click="CloseTemplate" class="btn btn-danger">
                                <em class="fa fa-times pr-2" aria-hidden="true"></em> {{ $t('Close') }}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </transition>
</div>
</template>

