    created: async function () {
        var vm = this;
        await vm.GetInvoiceLineItem();
    },
    methods: {
        GetInvoiceLineItem: async function () {
            var vm = this;
            var params = `lineBatchId=&billID=&lineItemId=${vm.lineItemId}&columnId=${vm.columnId}&ticketType=&isTicketMannual=`;
            await DataServices.GetInvoiceLineItem(params).then((response) => {
                if (response.data.length > 0) {
                    vm.InvoiceLineItemData = response.data[0];
                    vm.FormSchema[0].Data[0].value = vm.InvoiceLineItemData.TICKETNUMBER;
                    vm.FormSchema[0].Data[1].value = vm.InvoiceLineItemData.ACTIVITY_ID;
                    vm.FormSchema[0].Data[2].value = vm.InvoiceLineItemData.DESCRIPTION;
                    vm.FormSchema[0].Data[3].value = vm.InvoiceLineItemData.STATUS_CODE;
                    vm.FormSchema[0].Data[4].value = vm.InvoiceLineItemData.CLIENT_ID;
                    vm.FormSchema[0].Data[5].value = vm.InvoiceLineItemData.TICKET_ID;
                    vm.FormSchema[0].Data[6].value = vm.InvoiceLineItemData.LOCATOR_NAME;
                    vm.FormSchema[0].Data[7].value = vm.InvoiceLineItemData.STREETNAME;
                    vm.FormSchema[0].Data[8].value = vm.InvoiceLineItemData.FEEDNAME;
                    vm.FormSchema[0].Data[9].value = vm.InvoiceLineItemData.TRANSMISSION_ID;
