                    vm.FormSchema[0].Data[12].value = vm.InvoiceLineItemData.CALL_DATE;
                    vm.FormSchema[0].Data[13].value = vm.InvoiceLineItemData.TRANSMIT_DATE;
                    vm.FormSchema[0].Data[14].value = vm.InvoiceLineItemData.WORK_DATE;
                    vm.FormSchema[0].Data[15].value = vm.InvoiceLineItemData.PARSE_DATE;
                    vm.FormSchema[0].Data[16].value = vm.InvoiceLineItemData.COUNTY;
                    vm.FormSchema[0].Data[17].value = vm.InvoiceLineItemData.STATE;
                    vm.FormSchema[0].Data[18].value = vm.InvoiceLineItemData.CALLER_NAME;
                    vm.FormSchema[0].Data[19].value = vm.InvoiceLineItemData.CALLER_PHONE;
                    vm.FormSchema[0].Data[20].value = vm.InvoiceLineItemData.WORK_DONE_FOR;
                    vm.FormSchema[0].Data[21].value = vm.InvoiceLineItemData.EXCAVATOR;
                    vm.FormSchema[0].Data[22].value = vm.InvoiceLineItemData.TYPEOFWORK;
                    vm.FormSchema[0].Data[23].value = vm.InvoiceLineItemData.CLOSED_DATE;
                    vm.FormSchema[0].Data[24].value = vm.InvoiceLineItemData.INITIAL_STATUS_DATE;
                    vm.FormSchema[0].Data[25].value = vm.InvoiceLineItemData.LEGAL_DUE_DATE;
                    vm.FormSchema[0].Data[26].value = vm.InvoiceLineItemData.OUR_DUE_DATE;
                    vm.FormSchema[0].Data[27].value = vm.InvoiceLineItemData.UTILITY_NAME;
