                    vm.FormSchema[0].Data[29].value = vm.InvoiceLineItemData.MINUTES_WORKED;
                    vm.FormSchema[0].Data[30].value = vm.InvoiceLineItemData.EMERGENCY;
                    vm.FormSchema[0].Data[31].value = '';
