            var vm = this;
            vm.IsViewTicket = true;
            var TicketNumber = vm.InvoiceLineItemData.TICKETNUMBER;
            var TransmissionId = vm.InvoiceLineItemData.TRANSMISSION_ID;
            var url = `TicketNumber=${TicketNumber}&TransmissionId=${TransmissionId}`;
            DataServices.ViewTicketImage(url).then(response => {
