<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            loadKey: 0,
            LocationId: 0,
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Client"),
                            name: "Client",
                            value: "",
                            placeholder: this.$t('Client'),
                            mode: "tag",
                            config: {
                                options: [],
                                onChange: this.GetUtilityByClient
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Utility Name"),
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('UtilityName'),
                            mode: "tag",
                            config: {
                                options: []
                            }
                        },
                        {
                            astype: "SelectField",
                            label: this.$t("Cost Centres"),
                            name: "CostCentres",
                            value: "",
                            placeholder: this.$t('CostCentres'),
                            config: {
                                options: []
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "DateRangeField",
                            label: this.$t('Flag Date'),
                            name: "FlagDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Work_Date'),
                            name: "WorkDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "textField",
                            label: this.$t("Ticket Number"),
                            name: "TicketNumber",
                            value: "",
                            placeholder: "Ticket Number"
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                        astype: "SelectField",
                        label: this.$t("State"),
                        name: "State",
                        value: "",
                        placeholder: this.$t('State'),
                        config: {
                            options: []
                        }
                    }]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ],
            DataLoaded: 0,
        };
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetDDLStateList();
        await vm.GetCostCenters();
        await vm.GetClient();
    },
    methods: {
        formatDate(value) {
           if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "FlagFromDate") {
                vm.$refs.BarcodeReport.updateProperty("FlagToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "WorkDateFromdate") {
                vm.$refs.BarcodeReport.updateProperty("WorkDateToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }

        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];

            vm.FlagDateFrom = vm.$refs.BarcodeReport.getPropertyValue("FlagDateFrom", "value");
            vm.FlagDateTo = vm.$refs.BarcodeReport.getPropertyValue("FlagDateFrom", "secondValue");
            vm.WorkDateFrom = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "value");
            vm.WorkDateTo = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "secondValue");

            let myObj = {
                reportName: "flagsummaryreport",
                WorkDateFrom: vm.formatDate(vm.WorkDateFrom) ? vm.formatDate(vm.WorkDateFrom) : null,
                WorkDateTo: vm.formatDate(vm.WorkDateTo) ? vm.formatDate(vm.WorkDateTo) : null,
                dateFrom: vm.formatDate(vm.FlagDateFrom) ? vm.formatDate(vm.FlagDateFrom) : null,
                dateTo: vm.formatDate(vm.FlagDateTo) ? vm.formatDate(vm.FlagDateTo) : null,
                ClientIds: e.Client ? e.Client.toString() : '',
                UtilityIds: Array.isArray(e.UtilityName) && e.UtilityName.length > 0 ? e.UtilityName.map(item => item.value).join(",") : '',
                CostCenterId: e.CostCentres ? e.CostCentres.toString() : '',
                TicketNumber: e.TicketNumber || '',
                State: e.State ? e.State.toString() : ''
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[0].secondValue = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[2].Data[0].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        GetClient: async function () {
            var vm = this;
            var url = 'pageNumber=&pageSize=&Reqfrom=null&search=null&userId=null';
            await DataServices.GetClient(url).then((response) => {
                if (response.data.length > 0) {
                    var ClientData = response.data;
                    ClientData.forEach(element => {
                        var Obj = {
                            name: element.CHILD_NAME,
                            value: element.CHILD_USER_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetUtilityByClient: async function (x, y, z) {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options = [];
            vm.FormSchema[0].Data[1].value = '';
            var ClientIds = y.value;
            var url = `clientId=${ClientIds}&configid=0&Reqfrom=&clientIds=`;
            await DataServices.GetUtilityByClient(url).then((response) => {
                if (response.data.length > 0) {
                    var UtilityData = response.data;
                    UtilityData.forEach(element => {
                        var Obj = {
                            name: element.UTILITY_NAME,
                            value: element.UTILITY_ID
                        }
                        vm.FormSchema[0].Data[1].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetCostCenters: async function () {
            var vm = this;
            DataServices.GetCostCenters().then((response) => {
                if (response.data != '') {
                    var CostCentresData = response.data;
                    CostCentresData.forEach(item => {
                        vm.FormSchema[0].Data[2].config.options.push({
                            name: item.text,
                            value: item.value
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        GetDDLStateList: async function () {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            DataServices.GetDDLStateList(params).then((response) => {
                if (response.data.length > 0) {
                    var StateData = response.data;
                    StateData.forEach(item => {
                        vm.FormSchema[2].Data[0].config.options.push({
                            name: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                            value: item.ISO_CODE_3
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        }
    }
};
</script>